// Vintage Rangefinder Camera — a colorful BREP showcase.
// Layout (mm): ~80 wide (X) × 25 deep (Y) × 40 tall (Z), sitting on z=0.
// The camera's "front" face is +Y (toward the viewer when iso-rendered).
// Showcases: selective vertical-corner fillets on the body (inDirection
// workaround), a tapered cone lens barrel laid horizontally, a torus
// lens ring, a thin lens-glass cap, plus top-plate controls.
const { BREP } = api;

// =============== Body (the camera box) =================
// BREP.box([w,d,h]) is centred in X and Y but base at z=0.
const bodyW = 80, bodyD = 25, bodyH = 40;
const bodyRaw = BREP.box([bodyW, bodyD, bodyH]);
// Selective fillet on the four VERTICAL corners only (top + bottom rims
// stay sharp). The `inDirection: [0,0,1]` filter restricts to edges whose
// direction is parallel to Z — that's the workaround for the
// "inBox-on-box-edges" gotcha (planar coincident edges fail bbox tests).
const body = BREP.label(
  bodyRaw.fillet(3, { inDirection: [0, 0, 1] }),
  'body',
);

// =============== Top plate ==============================
// Slightly smaller than the body, sitting on top.
const tpW = 78, tpD = 24, tpH = 4;
const topPlate = BREP.label(
  BREP.box([tpW, tpD, tpH]).translate([0, 0, bodyH]),
  'top_plate',
);

// =============== Lens barrel (tapered cone) =============
// BREP.cone(rBottom, rTop, h): base at z=0 with radius 11, top at z=20
// with radius 9 — a subtle frustum taper toward the viewer.
// Default axis is +Z; we rotate -90° about X so the apex points to +Y
// (out the front of the body).  After rotate(-90, [1,0,0]):
//   +Z -> +Y  (so base ends up at y=0, top at y=20 along world Y).
const barrelH = 20;
const barrelRBase = 11, barrelRTop = 9;
const barrelLocal = BREP.cone(barrelRBase, barrelRTop, barrelH).rotate(-90, [1, 0, 0]);
// Center barrel vertically on the body, and slide it out the front so it
// pokes out from the front face (at y = bodyD/2 = +12.5).
// After rotate(-90,[1,0,0]) the cone's "base" sits at y=0; we want the
// base to be roughly flush with the body front so the barrel sticks out
// in +Y. Center on body height (z = bodyH/2 = 20).
const barrelCY = bodyD / 2;       // body front face is at y = +12.5
const barrelCZ = bodyH / 2;       // z = 20
// Sink the base 3mm into the body so the union is robust (>0.5 overlap).
const lensBarrel = BREP.label(
  barrelLocal.translate([0, barrelCY - 3, barrelCZ]),
  'lens_barrel',
);

// =============== Lens glass (flat cylinder cap) =========
// BREP.cylinder(r, h): axis +Z, base at z=0, height along +Z.
// We want a thin disc at the very FRONT of the barrel (y = barrelCY-3 + 20 = +29.5).
// Rotate -90° about X to make it axis-+Y, then translate to the front of the barrel.
// NOTE: deliberately NOT labelled — OCCT's face provenance propagates
// the label across the entire merged front cap into body triangles,
// painting big blue stripes across the leather. We paint the glass disc
// geometrically (paintInCylinder) in the paint phase instead.
const lensGlassR = 8, lensGlassH = 1;
const lensGlassY = barrelCY - 3 + barrelH - lensGlassH / 2;
const lensGlass = BREP.cylinder(lensGlassR, lensGlassH)
  .rotate(-90, [1, 0, 0])
  .translate([0, lensGlassY, barrelCZ]);

// =============== Lens ring (short cylindrical bezel) ===========
// Originally tried BREP.torus(12, 1.2), but the torus's tessellation
// produces dense fan triangles whose face-provenance leaks across the
// boolean — the `lens_ring` label ended up on ~65 % of the model, far
// past its real surface. A thin cylindrical bezel labels much cleaner
// (cylinder fans are radial-only and stay confined to the bezel face).
// Cylinder is axis-Z; rotate -90° about X to make axis-Y, then push it
// to the body front face so it rings the barrel base.
const ringR = 12, ringT = 1.2; // visible chrome ring 1.2 mm proud
const lensRing = BREP.label(
  BREP.cylinder(ringR, ringT)
    .rotate(-90, [1, 0, 0])
    .translate([0, barrelCY + 0.1, barrelCZ]),
  'lens_ring',
);

// =============== Viewfinder window =======================
// Small box on top-left of the FRONT face. Body's front face is at y=+12.5.
// We center it ~28mm to the left of the lens barrel and near the top of
// the body. Make it stick out 1.2 mm so the teal paint reads clearly.
const vfW = 7, vfD = 2, vfH = 5;
const viewfinder = BREP.label(
  BREP.box([vfW, vfD, vfH]).translate([
    -28,                          // shifted left of center
    bodyD / 2 + vfD / 2 - 0.5,    // proud of the front face (~+13.0)
    bodyH - vfH / 2 - 3,          // near the top of the body
  ]),
  'viewfinder',
);

// =============== Shutter button (chunky cylinder on top-right) ====
// Make it taller so the red paint is visible from the iso view, and
// give it a small radius — like a real rangefinder shutter.
const shutterR = 2.5, shutterH = 3;
const topPlateTopZ = bodyH + tpH; // 44
const shutterButton = BREP.label(
  BREP.cylinder(shutterR, shutterH).translate([
    28,                  // top-right of top plate (becomes top-left after Z flip)
    0,                   // centered front-to-back
    topPlateTopZ - 0.3,  // sits on top of plate, sunk slightly for solid fuse
  ]),
  'shutter_button',
);

// =============== Film advance lever (thin box behind shutter) ====
// Pointing along +X, slightly behind the shutter button (in -Y).
// Made taller (2 mm) and slightly longer so the chrome is visible.
const advW = 12, advD = 3, advH = 2;
const advance = BREP.label(
  BREP.box([advW, advD, advH]).translate([
    22,                       // top-right area
    -7,                       // behind shutter button (toward -Y / "back")
    topPlateTopZ - 0.3,       // resting on the top plate
  ]),
  'advance',
);

// =============== Final assembly ==========================
// Fuse all labeled pieces. Labels propagate through fuseAll.
// The iso thumbnail view is from (+X, -Y, +Z) looking at origin — so
// the "front" features (lens, viewfinder) need to be on -Y to face the
// camera. We built everything around y=+12.5 for clarity, then mirror
// the assembly around Y at the very end (rotate 180° about Z keeps
// labels intact and flips +Y -> -Y).
const assembled = BREP.fuseAll([
  body,
  topPlate,
  lensBarrel,
  lensRing,
  lensGlass,
  viewfinder,
  shutterButton,
  advance,
]);
return assembled.rotate(180, [0, 0, 1]);

